parsed.api_descriptions:
API_name: nchu_ge_course_search_by_keyword
Description:
{
  "description": "依關鍵字搜尋中興大學通識課程，可指定通識領域與學期。",
  "required_parameters": [
    {
      "name": "keyword",
      "type": "STRING",
      "description": "搜尋關鍵字"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "回傳結果上限",
      "default": 10
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "學年期代碼（如 1142）",
      "default": null
    },
    {
      "name": "include_syllabus_search",
      "type": "BOOLEAN",
      "description": "是否同時搜尋大綱內容",
      "default": false
    }
  ]
}

